        let wire = Wire.circle(radius: 5)!
        let wireShape = Shape.fromWire(wire)!
        let dim = DiameterDimension(shape: wireShape)
        if let dim = dim, let g = dim.geometry {
            #expect(g.circleRadius > 0)
