    func coincidentPoints() {
        let result = Shape.analyzePointCloud([
            SIMD3(5, 5, 5), SIMD3(5, 5, 5), SIMD3(5, 5, 5)
        ])
        #expect(result != nil)
        if case .point(let pt) = result {
