    }

    @Test func mirrorPoint() {
        guard let t = Transform2D.mirrorPoint(SIMD2(0, 0)) else { return }
        let result = t.apply(to: SIMD2(1, 2))
        #expect(abs(result.x + 1.0) < 1e-10)
        #expect(abs(result.y + 2.0) < 1e-10)
    }

    @Test func mirrorAxis() {
