        let roots = MathSolver.findAllRoots(in: -0.5...6.5, samples: 30) { x in
            (value: sin(x), derivative: cos(x))
        }
        #expect(roots.count >= 2)
    }
}

@Suite("MathSolver GaussIntegrate v0.111")
