            SIMD3(0.0, 0.0, 0.0), SIMD3(10.0, 0.0, 0.0),
            SIMD3(10.0, 10.0, 0.0), SIMD3(0.0, 10.0, 0.0)
        ]
        let curve = Curve3D.interpolatePeriodic(points: points)
        #expect(curve != nil)
    }
}

