        let q2 = SIMD4<Double>(0, 0, sin(.pi / 4), cos(.pi / 4)) // 90 deg about Z
        let mid = MathSolver.quaternionSlerp(from: q1, to: q2, t: 0.5)
        #expect(abs(mid.w) > 0.9) // close to 45 deg
    }

    @Test func nlerpEndpoints() {
