        let aabbVolume = aabbSize.x * aabbSize.y * aabbSize.z

        if let obb = rotated.orientedBoundingBox(optimal: true) {
            let obbVolume = 8.0 * obb.halfSizes.x * obb.halfSizes.y * obb.halfSizes.z
