@Suite("FilletBuilder v121")
struct FilletBuilderV121Tests {

    @Test("Create fillet builder and add edges with constant radius")
    func filletBuilderConstantRadius() {
        let box = Shape.box(width: 20, height: 20, depth: 20)
        #expect(box != nil)
        if let box = box {
            if let builder = FilletBuilder(shape: box) {
                let edges = box.edges()
                #expect(edges.count > 0)
                if let firstEdge = edges.first {
                    let added = builder.addEdge(firstEdge, radius: 2.0)
                    #expect(added)
                    #expect(builder.contourCount == 1)
                    #expect(builder.isConstant(contour: 1))
                    #expect(abs(builder.radius(contour: 1) - 2.0) < 1e-10)

                    if let result = builder.build() {
                        #expect(result.isValid)
                    }
                }
            }
        }
    }

    @Test("Fillet builder with evolving radius")
    func filletBuilderEvolvingRadius() {
        let box = Shape.box(width: 20, height: 20, depth: 20)
        if let box = box {
            if let builder = FilletBuilder(shape: box) {
                let edges = box.edges()
                if let edge = edges.first {
                    let added = builder.addEdge(edge, radius1: 1.0, radius2: 3.0)
                    #expect(added)
                    #expect(builder.contourCount == 1)
                    #expect(!builder.isConstant(contour: 1))

                    if let result = builder.build() {
                        #expect(result.isValid)
                    }
                }
            }
        }
    }

    @Test("Fillet builder multiple edges")
    func filletBuilderMultipleEdges() {
        let box = Shape.box(width: 20, height: 20, depth: 20)
        if let box = box {
            if let builder = FilletBuilder(shape: box) {
                let edges = box.edges()
                var addedCount = 0
                for edge in edges.prefix(3) {
                    if builder.addEdge(edge, radius: 1.5) {
                        addedCount += 1
                    }
                }
                #expect(addedCount > 0)
                #expect(builder.contourCount > 0)

                if let result = builder.build() {
                    #expect(result.isValid)
                }
            }
        }
    }

    @Test("Fillet builder query and diagnostic properties")
    func filletBuilderDiagnostics() {
        let box = Shape.box(width: 20, height: 20, depth: 20)
        if let box = box {
            if let builder = FilletBuilder(shape: box) {
                let edges = box.edges()
                if let edge = edges.first {
                    builder.addEdge(edge, radius: 2.0)
                    #expect(builder.edgeCount(contour: 1) >= 1)
                    #expect(builder.length(contour: 1) > 0)
                    #expect(builder.faultyContourCount == 0)
                    #expect(builder.faultyVertexCount == 0)
                }
            }
        }
    }

    @Test("Fillet builder reset")
    func filletBuilderReset() {
        let box = Shape.box(width: 20, height: 20, depth: 20)
        if let box = box {
            if let builder = FilletBuilder(shape: box) {
                let edges = box.edges()
                if let edge = edges.first {
                    builder.addEdge(edge, radius: 2.0)
                    #expect(builder.contourCount == 1)
                    // Reset clears build state but contours remain — verify no crash
                    builder.reset()
                    // Can still build after reset
                    if let result = builder.build() {
                        #expect(result.isValid)
                    }
                }
            }
        }
    }

    @Test("Fillet builder remove edge")
    func filletBuilderRemoveEdge() {
        let box = Shape.box(width: 20, height: 20, depth: 20)
        if let box = box {
            if let builder = FilletBuilder(shape: box) {
                let edges = box.edges()
                if let edge = edges.first {
                    builder.addEdge(edge, radius: 2.0)
                    #expect(builder.contourCount == 1)
                    let removed = builder.removeEdge(edge)
                    #expect(removed)
                    #expect(builder.contourCount == 0)
                }
            }
        }
    }
}

@Suite("ChamferBuilder v121")
struct ChamferBuilderV121Tests {

    @Test("Create chamfer builder with symmetric distance")
    func chamferBuilderSymmetric() {
        let box = Shape.box(width: 20, height: 20, depth: 20)
        if let box = box {
            if let builder = ChamferBuilder(shape: box) {
                let edges = box.edges()
                if let edge = edges.first {
                    let added = builder.addEdge(edge, distance: 2.0)
                    #expect(added)
                    #expect(builder.contourCount == 1)

                    if let result = builder.build() {
                        #expect(result.isValid)
                    }
                }
            }
        }
    }

    @Test("Chamfer builder with two distances")
    func chamferBuilderTwoDists() {
        let box = Shape.box(width: 20, height: 20, depth: 20)
        if let box = box {
            if let builder = ChamferBuilder(shape: box) {
                let edges = box.edges()
                let faces = box.faces()
                // Find an edge and a face sharing that edge
                if let edge = edges.first, let face = faces.first {
                    let added = builder.addEdge(edge, face: face, distance1: 2.0, distance2: 3.0)
                    #expect(added)
                    if added {
                        #expect(builder.contourCount == 1)
                        if let result = builder.build() {
                            #expect(result.isValid)
                        }
                    }
                }
            }
        }
    }

    @Test("Chamfer builder with distance and angle")
    func chamferBuilderDistAngle() {
        let box = Shape.box(width: 20, height: 20, depth: 20)
        if let box = box {
            if let builder = ChamferBuilder(shape: box) {
                let edges = box.edges()
                let faces = box.faces()
                if let edge = edges.first, let face = faces.first {
                    let angle = Double.pi / 4.0  // 45 degrees
                    let added = builder.addEdge(edge, face: face, distance: 2.0, angle: angle)
                    #expect(added)
                    if added {
                        #expect(builder.contourCount == 1)
                        #expect(builder.isDistanceAngle(contour: 1))
                        if let result = builder.build() {
                            #expect(result.isValid)
                        }
                    }
                }
            }
        }
    }

    @Test("Chamfer builder multiple edges")
    func chamferBuilderMultiple() {
        let box = Shape.box(width: 20, height: 20, depth: 20)
        if let box = box {
            if let builder = ChamferBuilder(shape: box) {
                let edges = box.edges()
                var addedCount = 0
                for edge in edges.prefix(4) {
                    if builder.addEdge(edge, distance: 1.0) {
                        addedCount += 1
                    }
                }
                #expect(addedCount > 0)
                if let result = builder.build() {
                    #expect(result.isValid)
                }
            }
        }
    }
}

// MARK: - GLTF Import/Export Tests (v0.121.0)

@Suite("GLTF Export/Import v121")
struct GLTFTests {
    @Test func exportGLB() throws {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            let tmpPath = NSTemporaryDirectory() + "test_v121.glb"
            let url = URL(fileURLWithPath: tmpPath)
            try Exporter.writeGLTF(shape: b, to: url, binary: true, deflection: 0.5)
            let data = try Data(contentsOf: url)
            #expect(data.count > 0)
            try? FileManager.default.removeItem(at: url)
        }
    }

    @Test func exportGLTF() throws {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            let tmpPath = NSTemporaryDirectory() + "test_v121.gltf"
            let url = URL(fileURLWithPath: tmpPath)
            try Exporter.writeGLTF(shape: b, to: url, binary: false, deflection: 0.5)
            let data = try Data(contentsOf: url)
            #expect(data.count > 0)
            // GLTF text format should contain "asset"
            if let text = String(data: data, encoding: .utf8) {
                #expect(text.contains("asset"))
            }
            try? FileManager.default.removeItem(at: url)
        }
    }

    @Test func roundTripGLB() throws {
        let box = Shape.box(width: 10, height: 20, depth: 30)
        if let b = box {
            let tmpPath = NSTemporaryDirectory() + "test_roundtrip_v121.glb"
            let url = URL(fileURLWithPath: tmpPath)
            try Exporter.writeGLTF(shape: b, to: url, binary: true, deflection: 0.1)

            // Reimport — GLTF is mesh-based, produces triangulation faces not B-Rep
            let reimported = Shape.loadGLTF(from: url)
            // loadGLTF returns non-nil if file was successfully read
            #expect(reimported != nil)
            try? FileManager.default.removeItem(at: url)
        }
    }

    @Test func documentGLTFRoundTrip() throws {
        let box = Shape.box(width: 5, height: 5, depth: 5)
        if let b = box {
            let tmpPath = NSTemporaryDirectory() + "test_doc_v121.glb"
            let url = URL(fileURLWithPath: tmpPath)
            try Exporter.writeGLTF(shape: b, to: url, binary: true, deflection: 0.5)

            // Load as document — GLTF documents contain mesh data
            let doc = Document.loadGLTF(from: url)
            #expect(doc != nil)
            try? FileManager.default.removeItem(at: url)
        }
    }
}

// MARK: - v0.122.0: WireFixer extended, ShapeFix_Edge, BRepTools/BRepLib statics, History extended, Sewing extended

@Suite("v0.122.0 — WireFixer Extended")
struct WireFixerExtendedTests {
    // Helper: get a face and its wire from a box
    private func faceAndWire() -> (face: Shape, wire: Shape)? {
        guard let box = Shape.box(width: 10, height: 10, depth: 10) else { return nil }
        let faces = box.subShapes(ofType: .face)
        guard faces.count > 0 else { return nil }
        let face = faces[0]
        let wires = face.subShapes(ofType: .wire)
        guard wires.count > 0 else { return nil }
        return (face, wires[0])
    }

    @Test("Fix gaps 2D")
    func fixGaps2d() {
        if let (face, wire) = faceAndWire() {
            let fixer = WireFixer(wire: wire, face: face, precision: 1e-6)
            if let fix = fixer {
                let _ = fix.fixGaps2d()
                let result = fix.wire
                #expect(result != nil)
            }
        }
    }

    @Test("Fix seam")
    func fixSeam() {
        // Use cylinder which has seam edges
        let cyl = Shape.cylinder(radius: 5, height: 10)
        if let c = cyl {
            let faces = c.subShapes(ofType: .face)
            if faces.count > 0 {
                let face = faces[0]
                let wires = face.subShapes(ofType: .wire)
                if wires.count > 0 {
                    let fixer = WireFixer(wire: wires[0], face: face, precision: 1e-6)
                    if let fix = fixer {
                        let _ = fix.fixSeam(edgeIndex: 1)
                        let result = fix.wire
                        #expect(result != nil)
                    }
                }
            }
        }
    }

    @Test("Fix shifted")
    func fixShifted() {
        if let (face, wire) = faceAndWire() {
            let fixer = WireFixer(wire: wire, face: face, precision: 1e-6)
            if let fix = fixer {
                let _ = fix.fixShifted()
                let result = fix.wire
                #expect(result != nil)
            }
        }
    }

    @Test("Fix notched edges")
    func fixNotchedEdges() {
        if let (face, wire) = faceAndWire() {
            let fixer = WireFixer(wire: wire, face: face, precision: 1e-6)
            if let fix = fixer {
                let _ = fix.fixNotchedEdges()
                let result = fix.wire
                #expect(result != nil)
            }
        }
    }

    @Test("Fix tails with configuration")
    func fixTailsWithConfig() {
        if let (face, wire) = faceAndWire() {
            let fixer = WireFixer(wire: wire, face: face, precision: 1e-6)
            if let fix = fixer {
                fix.setMaxTailAngle(0.5)
                fix.setMaxTailWidth(0.01)
                let _ = fix.fixTails()
                let result = fix.wire
                #expect(result != nil)
            }
        }
    }
}

@Suite("v0.122.0 — ShapeFix_Edge Extended")
struct ShapeFixEdgeExtendedTests {
    @Test("Add and remove 3D curve")
    func addRemoveCurve3d() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            let edges = b.subShapes(ofType: .edge)
            #expect(edges.count > 0)
            if edges.count > 0 {
                let edge = edges[0]
                // Edge already has a 3D curve, remove it then add back
                let removed = Shape.fixEdgeRemoveCurve3d(edge)
                // May or may not succeed depending on edge type
                if removed {
                    let added = Shape.fixEdgeAddCurve3d(edge)
                    #expect(added)
                }
            }
        }
    }

    @Test("Add PCurve to edge on face")
    func addPCurve() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            let faces = b.subShapes(ofType: .face)
            let edges = b.subShapes(ofType: .edge)
            if faces.count > 0, edges.count > 0 {
                // PCurve may already exist; this should be safe to call
                let _ = Shape.fixEdgeAddPCurve(edges[0], face: faces[0], isSeam: false)
                // Just verify it doesn't crash
            }
        }
    }

    @Test("Remove PCurve from edge on face")
    func removePCurve() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            let faces = b.subShapes(ofType: .face)
            let edges = b.subShapes(ofType: .edge)
            if faces.count > 0, edges.count > 0 {
                let _ = Shape.fixEdgeRemovePCurve(edges[0], face: faces[0])
                // Just verify it doesn't crash
            }
        }
    }

    @Test("Fix reversed 2D curve")
    func fixReversed2d() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            let faces = b.subShapes(ofType: .face)
            let edges = b.subShapes(ofType: .edge)
            if faces.count > 0, edges.count > 0 {
                let _ = Shape.fixEdgeReversed2d(edges[0], face: faces[0])
                // Just verify it doesn't crash
            }
        }
    }
}

@Suite("v0.122.0 — BRepTools Statics")
struct BRepToolsStaticsTests {
    @Test("Clean triangulation")
    func cleanTriangulation() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            let _ = b.mesh(linearDeflection: 0.5)
            // Clean should remove the triangulation
            b.cleanTriangulation()
            // After cleaning, meshing again should work
            let mesh = b.mesh(linearDeflection: 0.5)
            #expect(mesh != nil)
        }
    }

    @Test("Remove internals")
    func removeInternals() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            b.removeInternals()
            #expect(b.isValid)
        }
    }

    @Test("Detect closedness of cylindrical face")
    func detectClosedness() {
        let cyl = Shape.cylinder(radius: 5, height: 10)
        if let c = cyl {
            let faces = c.subShapes(ofType: .face)
            // Cylinder lateral face should be closed in U
            for face in faces {
                let (isClosedU, isClosedV) = face.detectClosedness()
                // At least check it doesn't crash
                if isClosedU || isClosedV {
                    #expect(true)
                    return
                }
            }
            // Not finding a closed face is OK - detectClosedness was called without crash
            #expect(true)
        }
    }

    @Test("Evaluate and update tolerance")
    func evalAndUpdateTol() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            let faces = b.subShapes(ofType: .face)
            let edges = b.subShapes(ofType: .edge)
            if faces.count > 0, edges.count > 0 {
                let tol = Shape.evalAndUpdateTolerance(edge: edges[0], face: faces[0])
                #expect(tol >= 0)
            }
        }
    }

    @Test("Map 3D edge count")
    func map3DEdgeCount() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            let count = b.map3DEdgeCount
            #expect(count == 12) // A box has 12 edges
        }
    }

    @Test("Update face UV points")
    func updateFaceUVPoints() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            let faces = b.subShapes(ofType: .face)
            if faces.count > 0 {
                faces[0].updateFaceUVPoints()
                // Just verify no crash
                #expect(true)
            }
        }
    }

    @Test("Compare vertices")
    func compareVertices() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            let verts = b.subShapes(ofType: .vertex)
            if verts.count >= 2 {
                // Same vertex compared to itself
                let same = Shape.compareVertices(verts[0], verts[0])
                #expect(same)
                // Different vertices may not be equal
                let diff = Shape.compareVertices(verts[0], verts[1])
                #expect(!diff) // Typically different vertices of a box
            }
        }
    }

    @Test("Compare edges")
    func compareEdges() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            let edges = b.subShapes(ofType: .edge)
            if edges.count >= 2 {
                let same = Shape.compareEdges(edges[0], edges[0])
                #expect(same)
            }
        }
    }

    @Test("Is really closed")
    func isReallyClosed() {
        let cyl = Shape.cylinder(radius: 5, height: 10)
        if let c = cyl {
            let faces = c.subShapes(ofType: .face)
            let edges = c.subShapes(ofType: .edge)
            if faces.count > 0, edges.count > 0 {
                // Check some edge/face pair — result depends on geometry
                let _ = Shape.isReallyClosed(edge: edges[0], face: faces[0])
                #expect(true) // Just verify no crash
            }
        }
    }

    @Test("Update topology")
    func updateTopology() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let b = box {
            b.updateTopology()
            #expect(b.isValid)
        }
    }
}

