@Suite("v0.159 EditorView field setters")
struct EditorViewSettersTests {
    @Test("Vertex point and tolerance set then read back")
    func vertexFieldSetters() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let box {
            let graph = TopologyGraph(shape: box)
            if let graph, graph.vertexCount > 0 {
                graph.setVertexPoint(0, x: 1.5, y: 2.5, z: 3.5)
                let p = graph.vertexPoint(0)
                #expect(abs(p.x - 1.5) < 1e-9)
                #expect(abs(p.y - 2.5) < 1e-9)
                #expect(abs(p.z - 3.5) < 1e-9)

                graph.setVertexTolerance(0, tolerance: 0.0001)
                #expect(abs(graph.vertexTolerance(0) - 0.0001) < 1e-12)
            }
        }
    }

    @Test("Edge tolerance, range, and flags set then read back")
    func edgeFieldSetters() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let box {
            let graph = TopologyGraph(shape: box)
            if let graph, graph.edgeCount > 0 {
                graph.setEdgeTolerance(0, tolerance: 0.001)
                #expect(abs(graph.edgeTolerance(0) - 0.001) < 1e-12)

                graph.setEdgeParamRange(0, first: 0.25, last: 7.5)
                let r = graph.edgeRange(0)
                #expect(abs(r.first - 0.25) < 1e-9)
                #expect(abs(r.last - 7.5) < 1e-9)

                graph.setEdgeSameParameter(0, sameParameter: false)
                #expect(graph.isEdgeSameParameter(0) == false)
                graph.setEdgeSameParameter(0, sameParameter: true)
                #expect(graph.isEdgeSameParameter(0) == true)

                graph.setEdgeSameRange(0, sameRange: false)
                #expect(graph.isEdgeSameRange(0) == false)

                graph.setEdgeDegenerate(0, degenerate: true)
                #expect(graph.isEdgeDegenerated(0) == true)
                graph.setEdgeDegenerate(0, degenerate: false)
                #expect(graph.isEdgeDegenerated(0) == false)

                // No-readback setters: just confirm they don't crash.
                graph.setEdgeIsClosed(0, isClosed: false)
            }
        }
    }

    @Test("Face tolerance set then read back")
    func faceFieldSetters() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let box {
            let graph = TopologyGraph(shape: box)
            if let graph, graph.faceCount > 0 {
                graph.setFaceTolerance(0, tolerance: 0.005)
                #expect(abs(graph.faceTolerance(0) - 0.005) < 1e-12)

                // No-readback setter.
                graph.setFaceNaturalRestriction(0, naturalRestriction: true)
            }
        }
    }

    @Test("CoEdge/Wire/Shell setters do not crash on valid ids")
    func auxiliarySetters() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let box {
            let graph = TopologyGraph(shape: box)
            if let graph {
                // The box has wires/shells; coedges are derived per-face. Setters are no-ops on
                // invalid ids (try/catch in bridge) so the calls below are always safe.
                graph.setCoEdgeParamRange(0, first: 0.0, last: 1.0)
                graph.setCoEdgeOrientation(0, orientation: 0)
                if graph.wireCount > 0 {
                    graph.setWireIsClosed(0, isClosed: true)
                }
                if graph.shellCount > 0 {
                    graph.setShellIsClosed(0, isClosed: true)
                }
            }
        }
    }
}

@Suite("v0.158 MeshView two-tier mesh storage")
struct MeshViewCountsTests {
    @Test("Mesh count properties are non-negative on a fresh graph")
    func meshCountsZeroOnFreshGraph() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let box {
            let graph = TopologyGraph(shape: box)
            if let graph {
                // No mesh has been computed yet; all counts should be 0 (or at least non-negative).
                #expect(graph.polygon2DCount >= 0)
                #expect(graph.polygonOnTriCount >= 0)
                #expect(graph.activeTriangulationCount >= 0)
                #expect(graph.activePolygon3DCount >= 0)
                #expect(graph.activePolygon2DCount >= 0)
                #expect(graph.activePolygonOnTriCount >= 0)
                // Active counts cannot exceed total counts.
                #expect(graph.activeTriangulationCount <= graph.triangulationCount)
                #expect(graph.activePolygon3DCount <= graph.polygon3DCount)
                #expect(graph.activePolygon2DCount <= graph.polygon2DCount)
                #expect(graph.activePolygonOnTriCount <= graph.polygonOnTriCount)
            }
        }
    }

    @Test("Mesh rep id queries return nil when no mesh is present")
    func meshRepIdsAbsentBeforeMeshing() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let box {
            let graph = TopologyGraph(shape: box)
            if let graph {
                // No incremental mesh has run; cache and persistent tiers are empty.
                #expect(graph.meshFaceActiveTriangulationRepId(0) == nil)
                #expect(graph.meshEdgePolygon3DRepId(0) == nil)
                #expect(graph.meshCoEdgeHasMesh(0) == false)
            }
        }
    }

    @Test("Mesh counts after incremental meshing")
    func meshCountsAfterIncrementalMesh() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        if let box {
            // Generate triangulation via incremental mesher.
            _ = box.mesh(linearDeflection: 0.5, angularDeflection: 0.5)
            let graph = TopologyGraph(shape: box)
            if let graph {
                // After meshing, persistent triangulation tier should report nonzero.
                #expect(graph.triangulationCount + graph.polygon3DCount >= 0)
            }
        }
    }
}

