        if let box = Shape.box(width: 10, height: 10, depth: 10) {
            if let graph = TopologyGraph(shape: box) {
                let origVertexCount = graph.vertexCount
                if let vidx = graph.addVertex(x: 5.0, y: 5.0, z: 5.0, tolerance: 1e-7) {
                    #expect(vidx >= 0)
