@Suite("Distance Solution Detail")
struct DistanceSolutionDetailTests {
    @Test func detailBetweenBoxes() {
        let box1 = Shape.box(width: 10, height: 10, depth: 10)
        let box2 = Shape.box(width: 5, height: 5, depth: 5)
        if let box1, let box2 {
            let moved = box2.translated(by: SIMD3(20, 0, 0))
            if let moved {
                let solutions = box1.allDistanceSolutions(to: moved)
                if let solutions, solutions.count > 0 {
                    let detail = box1.distanceSolutionDetail(to: moved, solutionIndex: 0)
                    #expect(detail != nil)
                    if let detail {
                        #expect(detail.supportType1.rawValue >= 0)
                        #expect(detail.supportType2.rawValue >= 0)
                    }
                }
            }
        }
    }

    @Test func detailSupportTypes() {
        let box = Shape.box(width: 10, height: 10, depth: 10)
        let sphere = Shape.sphere(radius: 3)
        if let box, let sphere {
            let moved = sphere.translated(by: SIMD3(20, 5, 5))
            if let moved {
                let detail = box.distanceSolutionDetail(to: moved, solutionIndex: 0)
                #expect(detail != nil)
            }
        }
    }
}

// MARK: - Curve3D Arc Length

@Suite("Curve3D Arc Length")
struct Curve3DArcLengthTests {
    @Test func totalArcLength() {
        let line = Curve3D.segment(from: SIMD3(0, 0, 0), to: SIMD3(10, 0, 0))
        if let line {
            let len = line.totalArcLength
            #expect(abs(len - 10.0) < 0.01)
        }
    }

    @Test func arcLengthBetween() {
        let line = Curve3D.segment(from: SIMD3(0, 0, 0), to: SIMD3(10, 0, 0))
        if let line {
            let d = line.domain
            let half = line.arcLengthBetween(d.lowerBound, (d.lowerBound + d.upperBound) / 2)
            #expect(abs(half - 5.0) < 0.01)
        }
    }

    @Test func parameterAtLength() {
        let line = Curve3D.segment(from: SIMD3(0, 0, 0), to: SIMD3(10, 0, 0))
        if let line {
            let midParam = line.parameterAtLength(5.0)
            let midPt = line.point(at: midParam)
            #expect(abs(midPt.x - 5.0) < 0.01)
        }
    }

    @Test func parameterAtLengthCircle() {
        let circle = Curve3D.circle(center: SIMD3(0, 0, 0), normal: SIMD3(0, 0, 1), radius: 10)
        if let circle {
            let circumference = circle.totalArcLength
            #expect(abs(circumference - 2 * Double.pi * 10) < 0.1)
            // Quarter arc length should give pi/2 parameter
            let quarterLen = circumference / 4
            let param = circle.parameterAtLength(quarterLen)
            let pt = circle.point(at: param)
            #expect(abs(pt.x) < 0.1)
            #expect(abs(pt.y - 10.0) < 0.1)
        }
    }
}

// MARK: - v0.137 Ch1: Surface axis extraction (#65)

@Suite("v0.137 Face.primaryAxis")
struct FacePrimaryAxisTests {
    @Test("Cylinder face has cylinder-kind primary axis along Z")
    func cylinderFacePrimaryAxis() {
        guard let cyl = Shape.cylinder(radius: 5, height: 10) else { Issue.record("cylinder nil"); return }
        var foundCyl = false
        for face in cyl.faces() where face.surfaceType == Face.SurfaceType.cylinder {
            if let axis = face.primaryAxis {
                #expect(axis.kind == ShapeAxis.Kind.cylinder)
                #expect(abs(axis.direction.z - 1.0) < 1e-6 || abs(axis.direction.z + 1.0) < 1e-6)
                foundCyl = true
            }
        }
        #expect(foundCyl)
    }

    @Test("Torus face exposes axis")
    func torusFacePrimaryAxis() {
        guard let torus = Shape.torus(majorRadius: 20, minorRadius: 5) else { Issue.record("torus nil"); return }
        var found = false
        for face in torus.faces() where face.surfaceType == Face.SurfaceType.torus {
            if let axis = face.primaryAxis {
                #expect(axis.kind == ShapeAxis.Kind.torus)
                found = true
            }
        }
        #expect(found)
    }

    @Test("Plane face has no primary axis")
    func planeFaceNoAxis() {
        guard let box = Shape.box(width: 10, height: 10, depth: 10) else { Issue.record("box nil"); return }
        for face in box.faces() where face.surfaceType == Face.SurfaceType.plane {
            #expect(face.primaryAxis == nil)
        }
    }
}

@Suite("v0.137 Shape.revolutionAxes")
struct ShapeRevolutionAxesTests {
    @Test("Cylinder yields exactly one axis")
    func cylinderOneAxis() {
        guard let cyl = Shape.cylinder(radius: 5, height: 10) else { Issue.record("cylinder nil"); return }
        let axes = cyl.revolutionAxes()
        #expect(axes.count == 1)
        if let a = axes.first {
            #expect(a.kind == ShapeAxis.Kind.cylinder)
            #expect(abs(a.direction.z - 1.0) < 1e-6 || abs(a.direction.z + 1.0) < 1e-6)
        }
    }

    @Test("Box yields no revolution axes")
    func boxNoAxes() {
        guard let box = Shape.box(width: 10, height: 10, depth: 10) else { Issue.record("box nil"); return }
        #expect(box.revolutionAxes().isEmpty)
    }

    @Test("Torus yields one deduplicated axis")
    func torusDedupedAxis() {
        guard let torus = Shape.torus(majorRadius: 20, minorRadius: 5) else { Issue.record("torus nil"); return }
        let axes = torus.revolutionAxes()
        #expect(axes.count >= 1)
        #expect(axes.contains { $0.kind == .torus })
    }

    @Test("Coaxial cylinder + torus collapse to one axis")
    func coaxialDedup() {
        guard let cyl = Shape.cylinder(radius: 5, height: 20),
              let torus = Shape.torus(majorRadius: 10, minorRadius: 2),
              let combined = cyl.union(with: torus) else { Issue.record("union nil"); return }
        let axes = combined.revolutionAxes()
        // Both share the Z axis at the origin → dedup to 1.
        #expect(axes.count == 1)
    }
}

