            Issue.record("setup nil"); return
        }
        let result = top.addAutoDimensions(from: cyl, viewDirection: SIMD3(0, 0, 1))
        let diaCount = result.added.filter {
            if case .diameter = $0 { return true } else { return false }
        }.count
